// Validate the digest JSON OpenClaw POSTed before we render it.
// Output: { valid, errors[], digest }. An IF node downstream routes on `valid`.
const SEV = ['urgent', 'attention', 'info', 'done'];
const errors = [];
// n8n's Webhook node wraps the POST under `.body`; fall back to top level for manual/pinned test runs.
const raw = $input.first().json;
const d = (raw && raw.body) ? raw.body : raw;

const isArr = (x) => Array.isArray(x);

function checkItems(arr, path) {
  if (!isArr(arr)) { errors.push(path + ' must be an array'); return; }
  arr.forEach((it, i) => {
    if (typeof it !== 'object' || it === null) { errors.push(path + '[' + i + '] must be an object'); return; }
    if (!SEV.includes(it.severity)) errors.push(path + '[' + i + '].severity must be one of ' + SEV.join('|'));
    if (!it.chip) errors.push(path + '[' + i + '].chip is required');
    if (!it.title) errors.push(path + '[' + i + '].title is required');
  });
}

if (!d || typeof d !== 'object') errors.push('payload must be a JSON object');
if (!d || !d.date || !/^\d{4}-\d{2}-\d{2}$/.test(d.date)) errors.push('date must be a string in YYYY-MM-DD form');

const m = (d && d.metrics) || {};
['todayEvents', 'overdueTasks', 'priorityEmails', 'upcomingP1P2'].forEach((k) => {
  if (typeof m[k] !== 'number') errors.push('metrics.' + k + ' must be a number');
});

const sch = (d && d.schedule) || {};
if (!isArr(sch.allDay)) errors.push('schedule.allDay must be an array (use [] when empty)');
if (!isArr(sch.timed)) errors.push('schedule.timed must be an array (use [] when empty)');
(sch.timed || []).forEach((e, i) => { if (!e || !e.title) errors.push('schedule.timed[' + i + '].title is required'); });

checkItems(d && d.deadlines, 'deadlines');
checkItems(d && d.emails, 'emails');
checkItems(d && d.fyi, 'fyi');

const t = (d && d.todoist) || {};
['dueToday', 'overdue', 'upcoming'].forEach((k) => {
  if (!isArr(t[k])) errors.push('todoist.' + k + ' must be an array (use [] when empty)');
});

if (!d || !isArr(d.actions)) errors.push('actions must be an array (use [] when empty)');

return [{ json: { valid: errors.length === 0, errors, digest: d } }];

// Deterministically render the validated digest JSON to a self-contained HTML
// document and attach it as base64 binary for the Telegram node. All content
// fields are HTML-escaped here, in code -- not trusted from the model.
const d = $json.digest;

const esc = (s) => String(s == null ? '' : s)
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;').replace(/'/g, '&#39;');

const SEV = new Set(['urgent', 'attention', 'info', 'done']);
const sev = (s) => (SEV.has(s) ? s : 'info');
const chip = (severity, label) => '<span class="chip ' + sev(severity) + '">' + esc(label) + '</span>';
const metaLine = (meta) => meta ? '<div class="meta">' + esc(meta) + '</div>' : '';
const snippetLine = (snip) => snip ? '<div class="snippet">' + esc(snip) + '</div>' : '';
const quiet = (msg) => '<div class="quiet">' + esc(msg) + '</div>';

const item = (it) => `
      <div class="item">
        <div class="row">${chip(it.severity, it.chip)}<span class="title">${esc(it.title)}</span></div>
        ${metaLine(it.meta)}
        ${snippetLine(it.snippet)}
      </div>`;

const itemsOrQuiet = (arr, emptyMsg) => (arr && arr.length) ? arr.map(item).join('') : quiet(emptyMsg);

const schedule = d.schedule || { allDay: [], timed: [] };
const allDayHtml = (schedule.allDay && schedule.allDay.length)
  ? schedule.allDay.map((e) => `
      <div class="item">
        <div class="row"><span class="chip info">All day</span><span class="title">${esc(e.title)}</span></div>
        ${metaLine(e.meta)}
      </div>`).join('')
  : quiet('No all-day events found.');
const timedHtml = (schedule.timed && schedule.timed.length)
  ? schedule.timed.map((e) => `
      <div class="item">
        <div class="row"><span class="chip info">${esc(e.time)}</span><span class="title">${esc(e.title)}</span></div>
        ${metaLine(e.meta)}
      </div>`).join('')
  : quiet('No timed events today.');

const t = d.todoist || { dueToday: [], overdue: [], upcoming: [] };
const liList = (arr, emptyMsg) => (arr && arr.length)
  ? '<ul>' + arr.map((x) => '<li>' + esc(x) + '</li>').join('') + '</ul>'
  : quiet(emptyMsg);

const actions = (d.actions && d.actions.length)
  ? '<ul>' + d.actions.map((a) => '<li>' + esc(a) + '</li>').join('') + '</ul>'
  : quiet('No suggested actions.');

const m = d.metrics || {};
const weekday = d.weekday || d.date;

const html = `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Daily Digest - ${esc(d.date)}</title>
<style>
    :root {
      color-scheme: light;
      --ink: #1f2933; --muted: #627082; --line: #d8dee8; --paper: #f6f8fb;
      --card: #ffffff; --navy: #243b53; --teal: #157a6e; --gold: #b7791f;
      --red: #b42318; --green: #2f855a; --blue: #2563eb;
    }
    * { box-sizing: border-box; }
    body { margin: 0; background: var(--paper); color: var(--ink);
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif; line-height: 1.45; }
    .wrap { max-width: 980px; margin: 0 auto; padding: 28px 18px 44px; }
    header { border-bottom: 1px solid var(--line); padding-bottom: 16px; margin-bottom: 18px; }
    h1 { margin: 0 0 6px; color: var(--navy); font-size: 28px; }
    .subhead { color: var(--muted); font-size: 14px; }
    .summary { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 10px; margin: 18px 0 22px; }
    .metric { background: var(--card); border: 1px solid var(--line); border-radius: 8px; padding: 12px; }
    .metric b { display: block; font-size: 22px; color: var(--navy); }
    .metric span { color: var(--muted); font-size: 12px; text-transform: uppercase; letter-spacing: .04em; }
    section { background: var(--card); border: 1px solid var(--line); border-radius: 8px; padding: 16px; margin: 12px 0; }
    h2 { margin: 0 0 12px; color: var(--navy); font-size: 17px; }
    .item { border-top: 1px solid #edf1f6; padding: 11px 0; }
    .item:first-of-type { border-top: 0; padding-top: 0; }
    .row { display: flex; align-items: baseline; gap: 8px; flex-wrap: wrap; }
    .title { font-weight: 650; color: var(--ink); }
    .meta { color: var(--muted); font-size: 13px; margin-top: 3px; }
    .snippet { color: #374151; font-size: 14px; margin-top: 5px; }
    .chip { display: inline-block; border-radius: 999px; padding: 2px 8px; font-size: 12px; font-weight: 700;
      line-height: 1.7; border: 1px solid transparent; white-space: nowrap; }
    .urgent { color: var(--red); background: #fff1f0; border-color: #ffd2cf; }
    .attention { color: var(--gold); background: #fff8e6; border-color: #f6d68b; }
    .info { color: var(--blue); background: #eef4ff; border-color: #cfe0ff; }
    .done { color: var(--green); background: #edf7f1; border-color: #cce8d5; }
    .quiet { color: var(--muted); font-size: 14px; padding: 2px 0; }
    a { color: #1d4ed8; text-decoration: none; }
    a:hover { text-decoration: underline; }
    ul { margin: 6px 0 0 18px; padding: 0; }
    li { margin: 5px 0; }
    .task-grid { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 12px; }
    .task-col { border: 1px solid #edf1f6; border-radius: 8px; padding: 12px; min-width: 0; }
    .task-col h3 { margin: 0 0 8px; font-size: 14px; color: var(--navy); }
    footer { color: var(--muted); font-size: 12px; margin-top: 18px; text-align: center; }
    @media (max-width: 760px) {
      .summary, .task-grid { grid-template-columns: 1fr; }
      .wrap { padding: 18px 12px 32px; }
      h1 { font-size: 24px; } section { padding: 14px; }
    }
</style>
</head>
<body>
<main class="wrap">
<header>
<h1>Daily Digest</h1>
<div class="subhead">${esc(weekday)} &middot; Generated from calendar, email, and Todoist sources. Low-signal mail was filtered out.</div>
</header>
<div class="summary" aria-label="Digest summary">
<div class="metric"><b>${esc(m.todayEvents)}</b><span>Today events</span></div>
<div class="metric"><b>${esc(m.overdueTasks)}</b><span>Overdue tasks</span></div>
<div class="metric"><b>${esc(m.priorityEmails)}</b><span>Priority emails</span></div>
<div class="metric"><b>${esc(m.upcomingP1P2)}</b><span>Upcoming P1/P2</span></div>
</div>
<section><h2>Today&apos;s Schedule</h2>${allDayHtml}${timedHtml}</section>
<section><h2>Upcoming Deadlines / Time-Sensitive Items</h2>${itemsOrQuiet(d.deadlines, 'Nothing time-sensitive.')}</section>
<section><h2>Important Emails</h2>${itemsOrQuiet(d.emails, 'No priority emails.')}</section>
<section><h2>Todoist</h2>
<div class="task-grid">
<div class="task-col"><h3>Due Today</h3>${liList(t.dueToday, 'No Todoist tasks due today.')}</div>
<div class="task-col"><h3>Overdue</h3>${liList(t.overdue, 'Nothing overdue.')}</div>
<div class="task-col"><h3>P1/P2 Next 14 Days</h3>${liList(t.upcoming, 'Nothing upcoming.')}</div>
</div>
</section>
<section><h2>FYI / Low Priority</h2>${itemsOrQuiet(d.fyi, 'Nothing here.')}</section>
<section><h2>Suggested Actions</h2>${actions}</section>
<footer>Static local digest. Calendar, email, and task content was summarized and HTML-escaped in n8n before insertion.</footer>
</main>
</body>
</html>`;

const fileName = 'daily-digest-' + d.date + '.html';
const base64 = Buffer.from(html, 'utf8').toString('base64');

return [{
  json: { fileName, caption: 'Daily Digest - ' + d.date },
  binary: { data: { data: base64, mimeType: 'text/html', fileName, fileExtension: 'html' } },
}];
